    const int32_t *kernelSizePtr = attrs->GetAttrPointer<int32_t>(0);
    const int32_t *stridePtr     = attrs->GetAttrPointer<int32_t>(1);
    const int32_t *paddingPtr    = attrs->GetAttrPointer<int32_t>(2);
