    uint32_t k = static_cast<uint32_t>(*kernelSizePtr);
    uint32_t s = static_cast<uint32_t>((*stridePtr <= 0) ? *kernelSizePtr : *stridePtr);
    uint32_t p = static_cast<uint32_t>((*paddingPtr < 0) ? 0 : *paddingPtr);
